import { useState } from "react";
import axios from "axios";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [feedback, setFeedback] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handlePredict = async () => {
    if (!file) {
      alert("Upload audio first");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {
      setLoading(true);

      const res = await axios.post(
        "http://127.0.0.1:8000/predict",
        formData
      );

      setResult(res.data);
      setLoading(false);
    } catch (err) {
      console.error(err);
      alert("Backend error");
      setLoading(false);
    }
  };

  const sendFeedback = async () => {
    await axios.post("http://127.0.0.1:8000/feedback", {
      prediction: result.prediction,
      feedback: feedback,
    });

    alert("Feedback saved");
    setFeedback("");
  };

  return (
    <div style={{ background: "#f4f6f9", minHeight: "100vh", padding: "30px" }}>
      <h1 style={{ textAlign: "center", color: "#2c3e50" }}>
        🎧 Cognitive Load Detection
      </h1>

      {/* Upload Card */}
      <div style={card}>
        <h3>Upload Lecture Audio</h3>
        <input type="file" onChange={handleFileChange} />
        <br /><br />
        <button style={btn} onClick={handlePredict}>
          Analyze
        </button>

        {loading && <p>⏳ Processing...</p>}
      </div>

      {/* Results */}
      {result && (
        <div style={card}>
          <h2>Prediction: {result.prediction}</h2>

          <div style={{ display: "flex", gap: "20px" }}>
            <div style={box}>
              Low: {result.probability.low.toFixed(2)}
            </div>
            <div style={box}>
              Medium: {result.probability.medium.toFixed(2)}
            </div>
            <div style={box}>
              High: {result.probability.high.toFixed(2)}
            </div>
          </div>

          <h3>📘 Summary</h3>
          <p>{result.summary}</p>

          <h3>📝 Quiz</h3>
          <ul>
            {result.quiz.map((q, i) => (
              <li key={i}>{q}</li>
            ))}
          </ul>

          <h3>💬 Feedback</h3>
          <input
            value={feedback}
            onChange={(e) => setFeedback(e.target.value)}
            placeholder="Enter feedback"
            style={input}
          />
          <button style={btn} onClick={sendFeedback}>
            Submit
          </button>
        </div>
      )}
    </div>
  );
}

/* STYLES */
const card = {
  background: "white",
  padding: "20px",
  margin: "20px auto",
  maxWidth: "700px",
  borderRadius: "10px",
  boxShadow: "0px 2px 10px rgba(0,0,0,0.1)",
};

const btn = {
  padding: "10px 20px",
  background: "#3498db",
  color: "white",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer",
};

const box = {
  background: "#ecf0f1",
  padding: "10px",
  borderRadius: "5px",
};

const input = {
  padding: "8px",
  marginRight: "10px",
};

export default App;
